var surah025 = {
  number: 25,
  nameArabic: "al-Furqan",
  nameEnglish: "Al-Furqan",
  meaning: "The Criterion",
  totalAyahs: 77,
  ayahs: [
    { number: 1, arabic: "تَبَارَكَ ٱلَّذِى نَزَّلَ ٱلْفُرْقَانَ عَلَىٰ عَبْدِهِۦ لِيَكُونَ لِلْعَٰلَمِينَ نَذِيرًا", transliteration: "Tabaraka allathee nazzala alfurqana AAala AAabdihi liyakoona lilAAalameena natheeran", transliterationB: "Tabaarakal lazee nazzalal Furqaana 'alaa 'abdihee li yakoona lil'aalameena nazeera", english: "Blessed is He who sent down the criterion to His servant, that it may be an admonition to all creatures", romanUrdu: "Nihayat mutabarrak(ba-barakat) hai woh jisne yeh Furqan apne banday par nazil kiya taa-ke saarey jahan waalon ke liye nazeer(darr sunane wali/warner) ho" },
    { number: 2, arabic: "ٱلَّذِى لَهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَلَمْ يَتَّخِذْ وَلَدًۭا وَلَمْ يَكُن لَّهُۥ شَرِيكٌۭ فِى ٱلْمُلْكِ وَخَلَقَ كُلَّ شَىْءٍۢ فَقَدَّرَهُۥ تَقْدِيرًۭا", transliteration: "Allathee lahu mulku alssamawati waalardi walam yattakhith waladan walam yakun lahu shareekun fee almulki wakhalaqa kulla shayin faqaddarahu taqdeeran", transliterationB: "Allazee lahoo mulkus samaawaati wal ardi wa lam yattakhiz waladanw wa lam yakul lahoo shareekun filmulki wa khalaqa kulla shai'in faqaddarahoo taqdeeraa", english: "He to whom belongs the dominion of the heavens and the earth: no son has He begotten, nor has He a partner in His dominion: it is He who created all things, and ordered them in due proportions", romanUrdu: "Woh jo zameen aur aasmaano ki baadshahi ka malik hai, jisne kisi ko beta nahin banaya hai, jiske saath baadshahi mein koi shareek nahin hai, jisne har cheez ko paida kiya phir uski ek taqdeer muqarrar ki" },
    { number: 3, arabic: "وَٱتَّخَذُوا۟ مِن دُونِهِۦٓ ءَالِهَةًۭ لَّا يَخْلُقُونَ شَيْـًۭٔا وَهُمْ يُخْلَقُونَ وَلَا يَمْلِكُونَ لِأَنفُسِهِمْ ضَرًّۭا وَلَا نَفْعًۭا وَلَا يَمْلِكُونَ مَوْتًۭا وَلَا حَيَوٰةًۭ وَلَا نُشُورًۭا", transliteration: "Waittakhathoo min doonihi alihatan la yakhluqoona shayan wahum yukhlaqoona wala yamlikoona lianfusihim darran wala nafAAan wala yamlikoona mawtan wala hayatan wala nushooran", transliterationB: "Wattakhazoo min dooniheee aahihatal laa yakhluqoona shai'anw wa hum yukhlaqoona wa laa yamlikoona li anfusihim darranw wa laa naf'anw wa laa yamlikoona mawtanw wa laa hayaatanw wa laa nushooraa", english: "Yet have they taken, besides him, gods that can create nothing but are themselves created; that have no control of hurt or good to themselves; nor can they control death nor life nor resurrection", romanUrdu: "Logon ne usey chodh kar aisey mabood bana liye jo kisi cheez ko paida nahin karte balke khud paida kiye jatey hain, jo khud apne liye bhi kisi nafey (faidey) ya nuqsaan ka ikhtiyar nahin rakhte, jo na maar sakte hain na jila sakte hain, na marey (dead) huey ko phir utha sakte hain" },
    { number: 4, arabic: "وَقَالَ ٱلَّذِينَ كَفَرُوٓا۟ إِنْ هَٰذَآ إِلَّآ إِفْكٌ ٱفْتَرَىٰهُ وَأَعَانَهُۥ عَلَيْهِ قَوْمٌ ءَاخَرُونَ ۖ فَقَدْ جَآءُو ظُلْمًۭا وَزُورًۭا", transliteration: "Waqala allatheena kafaroo in hatha illa ifkun iftarahu waaAAanahu AAalayhi qawmun akharoona faqad jaoo thulman wazooran", transliterationB: "Wa qaalal lazeena kafarooo in haazaaa illaaa ifkunif taraahu wa a'aanahoo 'alaihi qawmun aakharoona faqad jaaa'oo zulmanw wa zooraa", english: "But the misbelievers say: \"Naught is this but a lie which he has forged, and others have helped him at it.\" In truth it is they who have put forward an iniquity and a falsehood", romanUrdu: "Jin logon ne Nabi ki baat maanne se inkaar kariya hai woh kehte hain ke yeh furqan ek mann ghadat cheez hai jisey is shaks ne aap hi ghadd liye hai aur kuch dusre logon ne is kaam mein iski madad ki hai.Bada zulm aur sakht jhoot hai jispar yeh log utar aaye hain" },
    { number: 5, arabic: "وَقَالُوٓا۟ أَسَٰطِيرُ ٱلْأَوَّلِينَ ٱكْتَتَبَهَا فَهِىَ تُمْلَىٰ عَلَيْهِ بُكْرَةًۭ وَأَصِيلًۭا", transliteration: "Waqaloo asateeru alawwaleena iktatabaha fahiya tumla AAalayhi bukratan waaseelan", transliterationB: "Wa qaalooo asaateerul awwaleenak tatabahaa fahiya tumlaa 'alaihi bukratanw wa aseelaa", english: "And they say: \"Tales of the ancients, which he has caused to be written: and they are dictated before him morning and evening", romanUrdu: "Kehte hain yeh purane logon ki likhi hui cheezein hain jinhein yeh shaks naqal (copy) karta hai aur woh isey subah o shaam sunayi jaati hain" },
    { number: 6, arabic: "قُلْ أَنزَلَهُ ٱلَّذِى يَعْلَمُ ٱلسِّرَّ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ إِنَّهُۥ كَانَ غَفُورًۭا رَّحِيمًۭا", transliteration: "Qul anzalahu allathee yaAAlamu alssirra fee alssamawati waalardi innahu kana ghafooran raheeman", transliterationB: "Qul anzalhul lazee ya'lamus sirra fis samaawaati wal-ard; innahoo kaana Ghafoorar Raheemaa", english: "Say: \"The (Qur'an) was sent down by Him who knows the mystery (that is) in the heavens and the earth: verily He is Oft-Forgiving, Most Merciful", romanUrdu: "(Aey Muhammad) Insey kaho ke “isey nazil kiya hai usne jo zameen aur aasmano ka bhed (secrets) jaanta hai”. Haqeeqat yeh hai ke woh bada gafoor ur raheem(Forgiving and Merciful) hai" },
    { number: 7, arabic: "وَقَالُوا۟ مَالِ هَٰذَا ٱلرَّسُولِ يَأْكُلُ ٱلطَّعَامَ وَيَمْشِى فِى ٱلْأَسْوَاقِ ۙ لَوْلَآ أُنزِلَ إِلَيْهِ مَلَكٌۭ فَيَكُونَ مَعَهُۥ نَذِيرًا", transliteration: "Waqaloo mali hatha alrrasooli yakulu alttaAAama wayamshee fee alaswaqi lawla onzila ilayhi malakun fayakoona maAAahu natheeran", transliterationB: "Wa qaaloo maa li haazar Rasooli yaakulut ta'aama wa yamshee fil aswaaq; law laaa unzila ilaihi malakun fa yakoona ma'ahoo nazeeraa", english: "And they say: \"What sort of a messenger is this, who eats food, and walks through the streets? Why has not an angel been sent down to him to give admonition with him", romanUrdu: "Kehte hain “yeh kaisa Rasool hai jo khana khata hai aur bazaaron mein chalta phirta hai? Kyun na iske paas koi Farishata bheja gaya jo iske saath rehta aur (na maannay walon ko) dhamkata" },
    { number: 8, arabic: "أَوْ يُلْقَىٰٓ إِلَيْهِ كَنزٌ أَوْ تَكُونُ لَهُۥ جَنَّةٌۭ يَأْكُلُ مِنْهَا ۚ وَقَالَ ٱلظَّٰلِمُونَ إِن تَتَّبِعُونَ إِلَّا رَجُلًۭا مَّسْحُورًا", transliteration: "Aw yulqa ilayhi kanzun aw takoonu lahu jannatun yakulu minha waqala alththalimoona in tattabiAAoona illa rajulan mashooran", transliterationB: "Aw yulqaaa ilaihi kanzun aw takoonu lahoo jannatuny yaakulu minhaa; wa qaalaz zaalimoona in tattabi'oona illaa rajulam mas hooraa", english: "Or (Why) has not a treasure been bestowed on him, or why has he (not) a garden for enjoyment?\" The wicked say: \"Ye follow none other than a man bewitched", romanUrdu: "Ya aur kuch nahin to iske liye koi khazana hi utaar diya jata, ya iske paas koi baagh (garden) hi hota jissey yeh (itminaan ki) rozi haasil karta”. Aur zaalim kehte hain “ tum log to ek sehar zadah (bewitched) aadmi ke peechey lag gaye ho”" },
    { number: 9, arabic: "ٱنظُرْ كَيْفَ ضَرَبُوا۟ لَكَ ٱلْأَمْثَٰلَ فَضَلُّوا۟ فَلَا يَسْتَطِيعُونَ سَبِيلًۭا", transliteration: "Onthur kayfa daraboo laka alamthala fadalloo fala yastateeAAoona sabeelan", transliterationB: "Unzur kaifa daraboo lakal amsaala fadalloo falaa yastatee'oona sabeelaa", english: "See what kinds of comparisons they make for thee! But they have gone astray, and never a way will they be able to find", romanUrdu: "Dekho, kaisi kaisi ajeeb hujjatein (arguments) yeh log tumhare aagey pesh kar rahey hain, aisey behke hain ke koi thikane ki baat inko nahin soojhti" },
    { number: 10, arabic: "تَبَارَكَ ٱلَّذِىٓ إِن شَآءَ جَعَلَ لَكَ خَيْرًۭا مِّن ذَٰلِكَ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ وَيَجْعَل لَّكَ قُصُورًۢا", transliteration: "Tabaraka allathee in shaa jaAAala laka khayran min thalika jannatin tajree min tahtiha alanharu wayajAAal laka qusooran", transliterationB: "Tabaarakal lazeee in shaaa'a ja'ala laka khairam min zaalika jannaatin tajree min tahtihal anhaaru wa yaj'al laka qusooraa", english: "Blessed is He who, if that were His will, could give thee better (things) than those,- Gardens beneath which rivers flow; and He could give thee palaces (secure to dwell in)", romanUrdu: "Bada ba-barakat hai woh jo agar chahe to inki tajweej-karda cheezon se bhi zyada badh chadh kar tumko de sakta hai, (ek nahin) bahut sarey baagh (gardens) jinke nichey nehrein behti hon, aur baday baday mahal" },
    { number: 11, arabic: "بَلْ كَذَّبُوا۟ بِٱلسَّاعَةِ ۖ وَأَعْتَدْنَا لِمَن كَذَّبَ بِٱلسَّاعَةِ سَعِيرًا", transliteration: "Bal kaththaboo bialssaAAati waaAAtadna liman kaththaba bialssaAAati saAAeeran", transliterationB: "Bal kazzaboo bis Saa'ati wa a'tadnaa liman kazzaba bis Saa'ati sa'eeraa", english: "Nay they deny the hour (of the judgment to come): but We have prepared a blazing fire for such as deny the hour", romanUrdu: "Asal baat yeh hai ke yeh log “Us ghadi” ko jhutla chuke hain aur jo us ghadi ko jhutlaye uske liye humne bhadakti hui aag muhaiyya kar rakkhi hai" },
    { number: 12, arabic: "إِذَا رَأَتْهُم مِّن مَّكَانٍۭ بَعِيدٍۢ سَمِعُوا۟ لَهَا تَغَيُّظًۭا وَزَفِيرًۭا", transliteration: "Itha raathum min makanin baAAeedin samiAAoo laha taghayyuthan wazafeeran", transliterationB: "Izaa ra'at hum mim ma kaanim ba'eedin sami'oo lahaa taghaiyuzanw wa zafeeraa", english: "When it sees them from a place far off, they will hear its fury and its ranging sigh", romanUrdu: "Woh jab dur se inko dekhegi to yeh uske gazab aur josh ki aawaazein sun lenge" },
    { number: 13, arabic: "وَإِذَآ أُلْقُوا۟ مِنْهَا مَكَانًۭا ضَيِّقًۭا مُّقَرَّنِينَ دَعَوْا۟ هُنَالِكَ ثُبُورًۭا", transliteration: "Waitha olqoo minha makanan dayyiqan muqarraneena daAAaw hunalika thubooran", transliterationB: "Wa izaaa ulqoo minhaa makaanan daiyiqam muqar raneena da'aw hunaalika subooraa", english: "And when they are cast, bound together into a constricted place therein, they will plead for destruction there and then", romanUrdu: "Aur jab yeh dast o pa-basta (zanjeeron mein jakde) usmein ek tangg jagah thoonse jayenge to apni maut ko pukarne lagenge" },
    { number: 14, arabic: "لَّا تَدْعُوا۟ ٱلْيَوْمَ ثُبُورًۭا وَٰحِدًۭا وَٱدْعُوا۟ ثُبُورًۭا كَثِيرًۭا", transliteration: "La tadAAoo alyawma thubooran wahidan waodAAoo thubooran katheeran", transliterationB: "Laa tad'ul yawma subooranw waahidanw wad'oo subooran kaseeraa", english: "This day plead not for a single destruction: plead for destruction oft-repeated", romanUrdu: "(us waqt insey kaha jayega ke) aaj ek maut ko nahin bahut si mauton ko pukaro" },
    { number: 15, arabic: "قُلْ أَذَٰلِكَ خَيْرٌ أَمْ جَنَّةُ ٱلْخُلْدِ ٱلَّتِى وُعِدَ ٱلْمُتَّقُونَ ۚ كَانَتْ لَهُمْ جَزَآءًۭ وَمَصِيرًۭا", transliteration: "Qul athalika khayrun am jannatu alkhuldi allatee wuAAida almuttaqoona kanat lahum jazaan wamaseeran", transliterationB: "Qul azaalika khairun am Jannatul khuldil latee wu'idal muttaqoon; kaanat lahum jazaaa'anw wa maseeraa", english: "Say: \"Is that best, or the eternal garden, promised to the righteous? for them, that is a reward as well as a goal (of attainment)", romanUrdu: "Insey pucho, yeh anjaam accha hai ya woh abadi jannat jiska wada khuda-tars parhezgaaron se kiya gaya hai? Jo unke aamal ki jaza aur unke safar ki aakhri mazil hogi" },
    { number: 16, arabic: "لَّهُمْ فِيهَا مَا يَشَآءُونَ خَٰلِدِينَ ۚ كَانَ عَلَىٰ رَبِّكَ وَعْدًۭا مَّسْـُٔولًۭا", transliteration: "Lahum feeha ma yashaoona khalideena kana AAala rabbika waAAdan masoolan", transliterationB: "Lahum feehaa maa yashaaa'oona khaalideen; kaana 'alaa Rabbika wa'dam mas'oolaa", english: "For them there will be therein all that they wish for: they will dwell (there) for aye: A promise to be prayed for from thy Lord", romanUrdu: "Jis mein unki har khwahish poori hogi, jismein woh hamesha hamesha rahenge, jiska ataa karna tumhare Rubb ke zimme ek wajib ul ada wada hai" },
    { number: 17, arabic: "وَيَوْمَ يَحْشُرُهُمْ وَمَا يَعْبُدُونَ مِن دُونِ ٱللَّهِ فَيَقُولُ ءَأَنتُمْ أَضْلَلْتُمْ عِبَادِى هَٰٓؤُلَآءِ أَمْ هُمْ ضَلُّوا۟ ٱلسَّبِيلَ", transliteration: "Wayawma yahshuruhum wama yaAAbudoona min dooni Allahi fayaqoolu aantum adlaltum AAibadee haolai am hum dalloo alssabeela", transliterationB: "Wa Yawma yahshuruhum wa maa ya'budoona min doonil lahi fa yaqoolu 'a-antum adlaltum 'ibaadee haaa'ulaaa'i am hum dallus sabeel", english: "The day He will gather them together as well as those whom they worship besides Allah, He will ask: \"Was it ye who let these My servants astray, or did they stray from the Path themselves", romanUrdu: "Aur woh wahi din hoga jabke (tumhara Rubb) in logon ko bhi ghair layega aur inke un maboodon ko bhi bula lega jinhein aaj yeh Allah ko chodh kar poojh rahey hain. Phir woh unse puchega “kya tumne mere in bandon ko gumraah kiya tha? Ya yeh khud raah-e-raast se bhatak gaye thay?”" },
    { number: 18, arabic: "قَالُوا۟ سُبْحَٰنَكَ مَا كَانَ يَنۢبَغِى لَنَآ أَن نَّتَّخِذَ مِن دُونِكَ مِنْ أَوْلِيَآءَ وَلَٰكِن مَّتَّعْتَهُمْ وَءَابَآءَهُمْ حَتَّىٰ نَسُوا۟ ٱلذِّكْرَ وَكَانُوا۟ قَوْمًۢا بُورًۭا", transliteration: "Qaloo subhanaka ma kana yanbaghee lana an nattakhitha min doonika min awliyaa walakin mattaAAtahum waabaahum hatta nasoo alththikra wakanoo qawman booran", transliterationB: "Qaaloo Subhaanaka maa kaana yambaghee lanaaa an nattakhiza min doonika min awliyaaa'a wa laakim matta'tahum wa aabaaa'ahum hattaa nasuz zikra wa kaanoo qawmam booraa", english: "They will say: \"Glory to Thee! not meet was it for us that we should take for protectors others besides Thee: But Thou didst bestow, on them and their fathers, good things (in life), until they forgot the Message: for they were a people (worthless and) lost", romanUrdu: "Woh arz karenge ke “ paak hai aap ki zaat, hamari to yeh bhi majaal na thi ke aap ke siwa kisi ko apna maula banayein, magar aap ne inko aur inke baap dada ko khoob saaman e zindagi diya hatta ke yeh sabaq bhool gaye aur shamat zadah hokar rahey”" },
    { number: 19, arabic: "فَقَدْ كَذَّبُوكُم بِمَا تَقُولُونَ فَمَا تَسْتَطِيعُونَ صَرْفًۭا وَلَا نَصْرًۭا ۚ وَمَن يَظْلِم مِّنكُمْ نُذِقْهُ عَذَابًۭا كَبِيرًۭا", transliteration: "Faqad kaththabookum bima taqooloona fama tastateeAAoona sarfan wala nasran waman yathlim minkum nuthiqhu AAathaban kabeeran", transliterationB: "Faqad kazzabookum bimaa taqooloona famaa tastatee'oona sarfanw wa laa nasraa; wa mai yazlim minkum nuziqhu 'azaaban kabeeraa", english: "(Allah will say): \"Now have they proved you liars in what ye say: so ye cannot avert (your penalty) nor (get) help.\" And whoever among you does wrong, him shall We cause to taste of a grievous Penalty", romanUrdu: "Yun jhutla denge woh (tumhare mabood) tumhari un baaton ko jo aaj tum keh rahey ho, phir tum na apni shamat (punishment) taal sakoge na kahin se madad paa sakoge. Aur jo bhi tum mein se zulm karey usey hum sakht azaab ka maza chakhayenge" },
    { number: 20, arabic: "وَمَآ أَرْسَلْنَا قَبْلَكَ مِنَ ٱلْمُرْسَلِينَ إِلَّآ إِنَّهُمْ لَيَأْكُلُونَ ٱلطَّعَامَ وَيَمْشُونَ فِى ٱلْأَسْوَاقِ ۗ وَجَعَلْنَا بَعْضَكُمْ لِبَعْضٍۢ فِتْنَةً أَتَصْبِرُونَ ۗ وَكَانَ رَبُّكَ بَصِيرًۭا", transliteration: "Wama arsalna qablaka mina almursaleena illa innahum layakuloona alttaAAama wayamshoona fee alaswaqi wajaAAalna baAAdakum libaAAdin fitnatan atasbiroona wakana rabbuka baseeran", transliterationB: "Wa maaa arsalnaa qablaka minal mursaleena illaaa innahum la yaakuloonat ta'aama wa yamshoona fil aswaaq; wa ja'alnaa ba'dakum liba'din fitnatan atasbiroon; wa kaana Rabbuka Baseera", english: "And the messengers whom We sent before thee were all (men) who ate food and walked through the streets: We have made some of you as a trial for others: will ye have patience? for Allah is One Who sees (all things)", romanUrdu: "(Aey Muhammad), tumse pehle jo Rasool bhi humne bheje thay woh sab bhi khana khane waley aur bazaaron mein chalne phirne waley log hi thay. Darasal humne tum logon ko ek dusre ke liye aazmaish ka zariya bana diya hai, kya tum sabar karte ho? Tumhara Rubb sab kuch dekhta hai" },
    { number: 21, arabic: "۞ وَقَالَ ٱلَّذِينَ لَا يَرْجُونَ لِقَآءَنَا لَوْلَآ أُنزِلَ عَلَيْنَا ٱلْمَلَٰٓئِكَةُ أَوْ نَرَىٰ رَبَّنَا ۗ لَقَدِ ٱسْتَكْبَرُوا۟ فِىٓ أَنفُسِهِمْ وَعَتَوْ عُتُوًّۭا كَبِيرًۭا", transliteration: "Waqala allatheena la yarjoona liqaana lawla onzila AAalayna almalaikatu aw nara rabbana laqadi istakbaroo fee anfusihim waAAataw AAutuwwan kabeeran", transliterationB: "Wa qaalal lazeena laa yarjoona liqaaa'anaa law laaa unzila 'alainal malaaa'ikatu awnaraa Rabbanaa; laqadistakbaroo feee anfusihim wa 'ataw 'utuwwan kabeeraa", english: "Such as fear not the meeting with Us (for Judgment) say: \"Why are not the angels sent down to us, or (why) do we not see our Lord?\" Indeed they have an arrogant conceit of themselves, and mighty is the insolence of their impiety", romanUrdu: "Jo log hamare huzoor pesh honay ka andesha nahin rakhte woh kehte hain “kyun na Farishte hamare paas bheje jayein? Ya phir hum apne Rubb ko dekhein? Bada ghamand le baithey yeh apne nafs mein aur hadd se guzar gaye yeh apni sarkashi mein" },
    { number: 22, arabic: "يَوْمَ يَرَوْنَ ٱلْمَلَٰٓئِكَةَ لَا بُشْرَىٰ يَوْمَئِذٍۢ لِّلْمُجْرِمِينَ وَيَقُولُونَ حِجْرًۭا مَّحْجُورًۭا", transliteration: "Yawma yarawna almalaikata la bushra yawmaithin lilmujrimeena wayaqooloona hijran mahjooran", transliterationB: "Yawma yarawnal malaaa 'ikata laa bushraa Yawma'izil lilmujrimeena wa yaqooloona hijram mahjooraa", english: "The Day they see the angels,- no joy will there be to the sinners that Day: The (angels) will say: \"There is a barrier forbidden (to you) altogether", romanUrdu: "Jis roz yeh Farishton ko dekhenge woh mujreemo ke liye kisi basharat (khush khabri) ka din na hoga, cheekh uthenge ke panaah-ba-khuda" },
    { number: 23, arabic: "وَقَدِمْنَآ إِلَىٰ مَا عَمِلُوا۟ مِنْ عَمَلٍۢ فَجَعَلْنَٰهُ هَبَآءًۭ مَّنثُورًا", transliteration: "Waqadimna ila ma AAamiloo min AAamalin fajaAAalnahu habaan manthooran", transliterationB: "Wa qadimnaaa ilaa maa 'amiloo min 'amalin faja'alnaahu habaaa'am mansooraa", english: "And We shall turn to whatever deeds they did (in this life), and We shall make such deeds as floating dust scattered about", romanUrdu: "Aur jo kuch bhi inka kiya dhara hai usey lekar hum gubaar(dust) ki tarah uda dengey" },
    { number: 24, arabic: "أَصْحَٰبُ ٱلْجَنَّةِ يَوْمَئِذٍ خَيْرٌۭ مُّسْتَقَرًّۭا وَأَحْسَنُ مَقِيلًۭا", transliteration: "Ashabu aljannati yawmaithin khayrun mustaqarran waahsanu maqeelan", transliterationB: "As haabul jannati yawma'izin khairum mustaqar ranw wa ahsanu maqeela", english: "The Companions of the Garden will be well, that Day, in their abode, and have the fairest of places for repose", romanUrdu: "Bas wahi log jo jannat ke mustahiq hain us din acchi jagaah thehrenge aur dopahar (mid-day) guzarne ko umdah muqaam payenge" },
    { number: 25, arabic: "وَيَوْمَ تَشَقَّقُ ٱلسَّمَآءُ بِٱلْغَمَٰمِ وَنُزِّلَ ٱلْمَلَٰٓئِكَةُ تَنزِيلًا", transliteration: "Wayawma tashaqqaqu alssamao bialghamami wanuzzila almalaikatu tanzeelan", transliterationB: "Wa Yawma tashaqqaqus samaaa'u bilghamaami wa nuzzilal malaaa'ikatu tanzeela", english: "The Day the heaven shall be rent asunder with clouds, and angels shall be sent down, descending (in ranks)", romanUrdu: "Aasmaan ko cheerta hua ek baadal us roz namudaar hoga aur Farishton ke parey ke parey (rank after rank) utaar diye jayenge" },
    { number: 26, arabic: "ٱلْمُلْكُ يَوْمَئِذٍ ٱلْحَقُّ لِلرَّحْمَٰنِ ۚ وَكَانَ يَوْمًا عَلَى ٱلْكَٰفِرِينَ عَسِيرًۭا", transliteration: "Almulku yawmaithin alhaqqu lilrrahmani wakana yawman AAala alkafireena AAaseeran", transliterationB: "Almulku Yawma'izinil haqqu lir Rahmaan; wa kaana Yawman'alal kaafireena 'aseeraa", english: "That Day, the dominion as of right and truth, shall be (wholly) for (Allah) Most Merciful: it will be a Day of dire difficulty for the misbelievers", romanUrdu: "Us roz haqeeqi baadshahi sirf rehman ki hogi aur woh munkireen ke liye bada sakht din hoga" },
    { number: 27, arabic: "وَيَوْمَ يَعَضُّ ٱلظَّالِمُ عَلَىٰ يَدَيْهِ يَقُولُ يَٰلَيْتَنِى ٱتَّخَذْتُ مَعَ ٱلرَّسُولِ سَبِيلًۭا", transliteration: "Wayawma yaAAaddu alththalimu AAala yadayhi yaqoolu ya laytanee ittakhathtu maAAa alrrasooli sabeelan", transliterationB: "Wa Yawma ya'adduz zaalimu 'alaa yadaihi yaqoolu yaa laitanit takhaztu ma'ar Rasooli sabeelaa", english: "The Day that the wrong-doer will bite at his hands, he will say, \"Oh! would that I had taken a (straight) path with the Messenger", romanUrdu: "Zaalim Insaan apna haath chabayega aur kahega “kaash maine Rasool ka saath diya hota" },
    { number: 28, arabic: "يَٰوَيْلَتَىٰ لَيْتَنِى لَمْ أَتَّخِذْ فُلَانًا خَلِيلًۭا", transliteration: "Ya waylata laytanee lam attakhith fulanan khaleelan", transliterationB: "Yaa wailataa laitanee lam attakhiz fulaanan khaleelaa", english: "Ah! woe is me! Would that I had never taken such a one for a friend", romanUrdu: "Haaye meri kambakhti, kaash maine falaan shaks ko dost na banaya hota" },
    { number: 29, arabic: "لَّقَدْ أَضَلَّنِى عَنِ ٱلذِّكْرِ بَعْدَ إِذْ جَآءَنِى ۗ وَكَانَ ٱلشَّيْطَٰنُ لِلْإِنسَٰنِ خَذُولًۭا", transliteration: "Laqad adallanee AAani alththikri baAAda ith jaanee wakana alshshaytanu lilinsani khathoolan", transliterationB: "Laqad adallanee 'aniz zikri ba'da iz jaaa'anee; wa kaanash Shaitaanu lil insaani khazoolaa", english: "He did lead me astray from the Message (of Allah) after it had come to me! Ah! the Evil One is but a traitor to man", romanUrdu: "Uske behkaye mein aakar maine woh naseehat na maani jo mere paas aayi thi. Shaytaan insaan ke haqq mein bada hi bewafa nikla”" },
    { number: 30, arabic: "وَقَالَ ٱلرَّسُولُ يَٰرَبِّ إِنَّ قَوْمِى ٱتَّخَذُوا۟ هَٰذَا ٱلْقُرْءَانَ مَهْجُورًۭا", transliteration: "Waqala alrrasoolu ya rabbi inna qawmee ittakhathoo hatha alqurana mahjooran", transliterationB: "Wa qaalar Rasoolu yaa Rabbi inna qawmit takhazoo haazal Qur-aana mahjooraa", english: "Then the Messenger will say: \"O my Lord! Truly my people took this Qur'an for just foolish nonsense", romanUrdu: "Aur Rasool kahega ke “Aey mere Rubb, meri qaum ke logon ne is Quran ko nishana tadheek bana liya tha (the object of their ridicule)”" },
    { number: 31, arabic: "وَكَذَٰلِكَ جَعَلْنَا لِكُلِّ نَبِىٍّ عَدُوًّۭا مِّنَ ٱلْمُجْرِمِينَ ۗ وَكَفَىٰ بِرَبِّكَ هَادِيًۭا وَنَصِيرًۭا", transliteration: "Wakathalika jaAAalna likulli nabiyyin AAaduwwan mina almujrimeena wakafa birabbika hadiyan wanaseeran", transliterationB: "Wa kazaalika ja'alnaa likulli Nabiyyin 'aduwwam minal mujrimeen; wa kafaa bi Rabbika haadiyanw wa naseeraa", english: "Thus have We made for every prophet an enemy among the sinners: but enough is thy Lord to guide and to help", romanUrdu: "(Aey Muhammad), humne to isi taraah mujreemo ko har Nabi ka dushman banaya hai , aur tumhare liye tumhara Rubb hi rehnumayi aur madad ko kaafi hai" },
    { number: 32, arabic: "وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَوْلَا نُزِّلَ عَلَيْهِ ٱلْقُرْءَانُ جُمْلَةًۭ وَٰحِدَةًۭ ۚ كَذَٰلِكَ لِنُثَبِّتَ بِهِۦ فُؤَادَكَ ۖ وَرَتَّلْنَٰهُ تَرْتِيلًۭا", transliteration: "Waqala allatheena kafaroo lawla nuzzila AAalayhi alquranu jumlatan wahidatan kathalika linuthabbita bihi fuadaka warattalnahu tarteelan", transliterationB: "Wa qaalal lazeena kafaroo law laa nuzzila 'alaihil Quraanu jumlatanw waahidah; kazaalika linusabbita bihee fu'aadaka wa rattalnaahu tarteelaa", english: "Those who reject Faith say: \"Why is not the Qur'an revealed to him all at once? Thus (is it revealed), that We may strengthen thy heart thereby, and We have rehearsed it to thee in slow, well-arranged stages, gradually", romanUrdu: "Munkireen kehte hain “is shaks par saara Quran ek hi waqt mein kyun na utaar diya gaya? Haan, aisa is liye kiya gaya hai ke isko achhi tarah hum tumhare zehan nasheen karte rahein aur (isi garaz ke liye) humne isko ek khaas tarteeb ke saath alag alag ajzaa ki shakal di hai" },
    { number: 33, arabic: "وَلَا يَأْتُونَكَ بِمَثَلٍ إِلَّا جِئْنَٰكَ بِٱلْحَقِّ وَأَحْسَنَ تَفْسِيرًا", transliteration: "Wala yatoonaka bimathalin illa jinaka bialhaqqi waahsana tafseeran", transliterationB: "Wa laa yaatoonaka bimasainn illaa ji'naaka bilhaqqi wa ahsana tafseeraa", english: "And no question do they bring to thee but We reveal to thee the truth and the best explanation (thereof)", romanUrdu: "Aur (ismein yeh maslihat bhi hai) ke jab kabhi woh tumhare samne koi nirali baat (ya ajeeb sawal) lekar aaye, uska theek jawaab bar waqt humne tumhein de diya aur behtareen tareeqe se baat khol di" },
    { number: 34, arabic: "ٱلَّذِينَ يُحْشَرُونَ عَلَىٰ وُجُوهِهِمْ إِلَىٰ جَهَنَّمَ أُو۟لَٰٓئِكَ شَرٌّۭ مَّكَانًۭا وَأَضَلُّ سَبِيلًۭا", transliteration: "Allatheena yuhsharoona AAala wujoohihim ila jahannama olaika sharrun makanan waadallu sabeelan", transliterationB: "(Allazeena yuhsharoona 'alaa wujoohim ilaa jahannama ulaaa'ika sharrum makaananw wa adallu sabeelaa )section", english: "Those who will be gathered to Hell (prone) on their faces,- they will be in an evil plight, and, as to Path, most astray", romanUrdu: "Jo log aundhey mooh jahannum ki taraf dhakele janey waley hain unka mauquf bahut bura (most erroneous) aur unki raah hadd darjah galat hai" },
    { number: 35, arabic: "وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ وَجَعَلْنَا مَعَهُۥٓ أَخَاهُ هَٰرُونَ وَزِيرًۭا", transliteration: "Walaqad atayna moosa alkitaba wajaAAalna maAAahu akhahu haroona wazeeran", transliterationB: "Wa laqad aatainaa Moosal Kitaaba wa ja'alnaa ma'ahooo akhaahu Haaroona wazeeraa", english: "(Before this,) We sent Moses The Book, and appointed his brother Aaron with him as minister", romanUrdu: "Humne Moosa ko kitaab di aur uske saath uske bhai Haroon ko madadgaar ke taur par lagaya" },
    { number: 36, arabic: "فَقُلْنَا ٱذْهَبَآ إِلَى ٱلْقَوْمِ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا فَدَمَّرْنَٰهُمْ تَدْمِيرًۭا", transliteration: "Faqulna ithhaba ila alqawmi allatheena kaththaboo biayatina fadammarnahum tadmeeran", transliterationB: "Faqulnaz habaaa ilal qawmil lazeena kazzaboo bi Aayaatinaa fadammarnaahum tadmeeraa", english: "And We command: \"Go ye both, to the people who have rejected our Signs:\" And those (people) We destroyed with utter destruction", romanUrdu: "Aur unse kaha ke jao us qaum ki taraf jisne hamari aayat ko jhutla diya hai. Aakhir e kaar un logon ko humne tabaah karke rakh diya" },
    { number: 37, arabic: "وَقَوْمَ نُوحٍۢ لَّمَّا كَذَّبُوا۟ ٱلرُّسُلَ أَغْرَقْنَٰهُمْ وَجَعَلْنَٰهُمْ لِلنَّاسِ ءَايَةًۭ ۖ وَأَعْتَدْنَا لِلظَّٰلِمِينَ عَذَابًا أَلِيمًۭا", transliteration: "Waqawma noohin lamma kaththaboo alrrusula aghraqnahum wajaAAalnahum lilnnasi ayatan waaAAtadna lilththalimeena AAathaban aleeman", transliterationB: "Wa qawma Noohil lammaa kazzabur Rusula aghraqnaahum wa ja'alnaahum linnaasi Aayatanw wa a'tadnaa lizzaalimeena 'azaaban aleemaa", english: "And the people of Noah,- when they rejected the messengers, We drowned them, and We made them as a Sign for mankind; and We have prepared for (all) wrong-doers a grievous Penalty", romanUrdu: "Yahi haal qaum e Nooh ka hua jab unhon ne Rasoolon ki takzeeb ki, humne unko garq (drown/duba) kardiya aur duniya bhar ke logon ke liye ek nishaan e ibrat bana diya, aur in zaalimon ke liye ek dardnaak azaab humne muhaiyya kar rakkha hai" },
    { number: 38, arabic: "وَعَادًۭا وَثَمُودَا۟ وَأَصْحَٰبَ ٱلرَّسِّ وَقُرُونًۢا بَيْنَ ذَٰلِكَ كَثِيرًۭا", transliteration: "WaAAadan wathamooda waashaba alrrassi waquroonan bayna thalika katheeran", transliterationB: "Wa 'Aadanw Samooda wa As haabar Rassi wa quroonam baina zaalika kaseeraa", english: "As also 'Ad and Thamud, and the Companions of the Rass, and many a generation between them", romanUrdu: "Isi tarah Aad aur Samood aur ashaab e Rass aur beech ki sadiyon ke bahut se log tabaah kiye gaye" },
    { number: 39, arabic: "وَكُلًّۭا ضَرَبْنَا لَهُ ٱلْأَمْثَٰلَ ۖ وَكُلًّۭا تَبَّرْنَا تَتْبِيرًۭا", transliteration: "Wakullan darabna lahu alamthala wakullan tabbarna tatbeeran", transliterationB: "Wa kullandarabnaa lahul amsaala wa kullan tabbarnaa tatbeera", english: "To each one We set forth Parables and examples; and each one We broke to utter annihilation (for their sins)", romanUrdu: "Aur un mein se har ek ko humne ( pehle tabaah honay walon ki) misalein dey dey kar samjhaya, aur aakhir e kaar har ek ko gaarat (destroy) kardiya" },
    { number: 40, arabic: "وَلَقَدْ أَتَوْا۟ عَلَى ٱلْقَرْيَةِ ٱلَّتِىٓ أُمْطِرَتْ مَطَرَ ٱلسَّوْءِ ۚ أَفَلَمْ يَكُونُوا۟ يَرَوْنَهَا ۚ بَلْ كَانُوا۟ لَا يَرْجُونَ نُشُورًۭا", transliteration: "Walaqad ataw AAala alqaryati allatee omtirat matara alssawi afalam yakoonoo yarawnaha bal kanoo la yarjoona nushooran", transliterationB: "Wa laqad ataw 'alal qaryatil lateee umtirat mataras saw'; afalam yakoonoo yarawnahaa; bal kaanoo laa yarjoona nushooraa", english: "And the (Unbelievers) must indeed have passed by the town on which was rained a shower of evil: did they not then see it (with their own eyes)? But they fear not the Resurrection", romanUrdu: "Aur us basti par to inka guzar ho chuka hai jispar badhtareen baarish barsayi gayi thi.Kya inhon ne uska haal dekha na hoga? Magar yeh maut ke baad dusri zindagi ki tawakku hi nahin rakhte" },
    { number: 41, arabic: "وَإِذَا رَأَوْكَ إِن يَتَّخِذُونَكَ إِلَّا هُزُوًا أَهَٰذَا ٱلَّذِى بَعَثَ ٱللَّهُ رَسُولًا", transliteration: "Waitha raawka in yattakhithoonaka illa huzuwan ahatha allathee baAAatha Allahu rasoolan", transliterationB: "Wa izaa ra awka iny yattakhizoonaka illaa huzuwan ahaazal lazee ba'asal laahu Rasoolaa", english: "When they see thee, they treat thee no otherwise than in mockery: \"Is this the one whom Allah has sent as a messenger", romanUrdu: "Yeh log jab tumhein dekhte hain to tumhara mazaaq bana lete hain, (Kehte hain) “kya yeh shaks hai jisey khuda ne Rasool bana kar bheja hai" },
    { number: 42, arabic: "إِن كَادَ لَيُضِلُّنَا عَنْ ءَالِهَتِنَا لَوْلَآ أَن صَبَرْنَا عَلَيْهَا ۚ وَسَوْفَ يَعْلَمُونَ حِينَ يَرَوْنَ ٱلْعَذَابَ مَنْ أَضَلُّ سَبِيلًا", transliteration: "In kada layudilluna AAan alihatina lawla an sabarna AAalayha wasawfa yaAAlamoona heena yarawna alAAathaba man adallu sabeelan", transliterationB: "In kaada la yudillunaa 'an aalihatinaa law laaa an sabarnaa 'alaihaa; wa sawfa ya'lamoona heena yarawnal 'azaaba man adallu sabeela", english: "He indeed would well-nigh have misled us from our gods, had it not been that we were constant to them!\" - Soon will they know, when they see the Penalty, who it is that is most misled in Path", romanUrdu: "Isne to humein gumraah karke apne maboodon se bargashta(astray/behka/gumrah) hi kardiya hota agar hum unki aqeedat par jam na gaye hotey”. Accha, woh waqt door nahin hai jab azaab dekh kar inhein khud maloom ho jayega ke kaun gumraahi mein door nikal gaya tha" },
    { number: 43, arabic: "أَرَءَيْتَ مَنِ ٱتَّخَذَ إِلَٰهَهُۥ هَوَىٰهُ أَفَأَنتَ تَكُونُ عَلَيْهِ وَكِيلًا", transliteration: "Araayta mani ittakhatha ilahahu hawahu afaanta takoonu AAalayhi wakeelan", transliterationB: "Ara'aita manit takhaza ilaahahoo hawaahu afa anta takoonu 'alaihi wakeelaa", english: "Seest thou such a one as taketh for his god his own passion (or impulse)? Couldst thou be a disposer of affairs for him", romanUrdu: "Kabhi tumne us shaks ke haal par gaur kiya hai jisne apni khwahish e nafs ko apna khuda bana liya ho? Kya tum aisey shaks ko raah e raast par laney ka zimma le sakte ho" },
    { number: 44, arabic: "أَمْ تَحْسَبُ أَنَّ أَكْثَرَهُمْ يَسْمَعُونَ أَوْ يَعْقِلُونَ ۚ إِنْ هُمْ إِلَّا كَٱلْأَنْعَٰمِ ۖ بَلْ هُمْ أَضَلُّ سَبِيلًا", transliteration: "Am tahsabu anna aktharahum yasmaAAoona aw yaAAqiloona in hum illa kaalanAAami bal hum adallu sabeelan", transliterationB: "Am tahsabu annna aksarahum yasma'oona aw ya''qiloon; in hum illaa kal an'aami bal hum adallu sabeelan", english: "Or thinkest thou that most of them listen or understand? They are only like cattle;- nay, they are worse astray in Path", romanUrdu: "Kya tum samajhte ho ke inmein se aksar log sunte aur samajhte hain? Yeh to jaanwaron ki tarah hain, balke unse bhi gaye guzre" },
    { number: 45, arabic: "أَلَمْ تَرَ إِلَىٰ رَبِّكَ كَيْفَ مَدَّ ٱلظِّلَّ وَلَوْ شَآءَ لَجَعَلَهُۥ سَاكِنًۭا ثُمَّ جَعَلْنَا ٱلشَّمْسَ عَلَيْهِ دَلِيلًۭا", transliteration: "Alam tara ila rabbika kayfa madda alththilla walaw shaa lajaAAalahu sakinan thumma jaAAalna alshshamsa AAalayhi daleelan", transliterationB: "Alam tara ilaa Rabbika kaifa maddaz zilla wa law shaaa'a laja'alahoo saakinan summa ja'alnash shamsa 'alaihe daleelaa", english: "Hast thou not turned thy vision to thy Lord?- How He doth prolong the shadow! If He willed, He could make it stationary! then do We make the sun its guide", romanUrdu: "Tumne dekha nahin ke tumhara Rubb kis tarah saaya phayla deta hai? Agar woh chahta to usey daimi (constant) bana deta. Humne Suraj ko uspar daleel (sun its pilot) banaya" },
    { number: 46, arabic: "ثُمَّ قَبَضْنَٰهُ إِلَيْنَا قَبْضًۭا يَسِيرًۭا", transliteration: "Thumma qabadnahu ilayna qabdan yaseeran", transliterationB: "Summa qabadnaahu ilainaa qabdany yaseeraa", english: "Then We draw it in towards Ourselves,- a contraction by easy stages", romanUrdu: "Phir (jaisey jaisey Suraj utha jaata hai) hum is saaye ko rafta rafta apni taraf sameit-te chale jatey hain" },
    { number: 47, arabic: "وَهُوَ ٱلَّذِى جَعَلَ لَكُمُ ٱلَّيْلَ لِبَاسًۭا وَٱلنَّوْمَ سُبَاتًۭا وَجَعَلَ ٱلنَّهَارَ نُشُورًۭا", transliteration: "Wahuwa allathee jaAAala lakumu allayla libasan waalnnawma subatan wajaAAala alnnahara nushooran", transliterationB: "Wa Huwal lazee ja'ala lakumul laila libaasanw wannawma subaatanw wa ja'alan nahaara nushooraa", english: "And He it is Who makes the Night as a Robe for you, and Sleep as Repose, and makes the Day (as it were) a Resurrection", romanUrdu: "Aur woh Allah hi hai jisne raat ko tumhare liye libaas, aur neend ko sukoon e maut, aur din ko jee uthne ka waqt banaya" },
    { number: 48, arabic: "وَهُوَ ٱلَّذِىٓ أَرْسَلَ ٱلرِّيَٰحَ بُشْرًۢا بَيْنَ يَدَىْ رَحْمَتِهِۦ ۚ وَأَنزَلْنَا مِنَ ٱلسَّمَآءِ مَآءًۭ طَهُورًۭا", transliteration: "Wahuwa allathee arsala alrriyaha bushran bayna yaday rahmatihi waanzalna mina alssamai maan tahooran", transliterationB: "Wa Huwal lazeee arsalar riyaaha bushram baina yadai rahmatih; wa anzalnaa minas samaaa'i maaa'an tahooraa", english: "And He it is Who sends the winds as heralds of glad tidings, going before His mercy, and We send down pure water from the sky", romanUrdu: "Aur wahi hai jo apni rehmat ke aagey aagey hawaon ko basharat bana kar bhejta hai phir aasmaan se paak pani nazil karta hai" },
    { number: 49, arabic: "لِّنُحْۦِىَ بِهِۦ بَلْدَةًۭ مَّيْتًۭا وَنُسْقِيَهُۥ مِمَّا خَلَقْنَآ أَنْعَٰمًۭا وَأَنَاسِىَّ كَثِيرًۭا", transliteration: "Linuhyiya bihi baldatan maytan wanusqiyahu mimma khalaqna anAAaman waanasiyya katheeran", transliterationB: "Linuhyiya bihee balda tam maitanw wa nusqiyahoo mimmaa khalaqnaaa an'aa manw wa anaasiyya kaseeraa", english: "That with it We may give life to a dead land, and slake the thirst of things We have created,- cattle and men in great numbers", romanUrdu: "Taa-ke ek murda ilake ko iske zariye zindagi bakshe aur apni makhlooq mein se bahut se jaanwaron aur Insano ko sairaab (quench thirst) karey" },
    { number: 50, arabic: "وَلَقَدْ صَرَّفْنَٰهُ بَيْنَهُمْ لِيَذَّكَّرُوا۟ فَأَبَىٰٓ أَكْثَرُ ٱلنَّاسِ إِلَّا كُفُورًۭا", transliteration: "Walaqad sarrafnahu baynahum liyaththakkaroo faaba aktharu alnnasi illa kufooran", transliterationB: "Wa laqad sarrafnaahu bainahum li yazzakkaroo fa abaaa aksarun naasi illaa kufooraa", english: "And We have distributed the (water) amongst them, in order that they may celebrate (our) praises, but most men are averse (to aught) but (rank) ingratitude", romanUrdu: "Is karishme ko hum baar baar inke saamne latey hain taa-ke woh kuch sabaq lein. Magar aksar log kufr aur nashukri ke siwa koi dusra rawaiyya ikhtiyar karne se inkar kardete hain" },
    { number: 51, arabic: "وَلَوْ شِئْنَا لَبَعَثْنَا فِى كُلِّ قَرْيَةٍۢ نَّذِيرًۭا", transliteration: "Walaw shina labaAAathna fee kulli qaryatin natheeran", transliterationB: "Wa law shi'naa laba'asnaa fee kulli qar yatin nazeeraa", english: "Had it been Our Will, We could have sent a warner to every centre of population", romanUrdu: "Agar hum chahte to ek ek basti mein ek ek nazeer (darr sunane waala) utha khada karte" },
    { number: 52, arabic: "فَلَا تُطِعِ ٱلْكَٰفِرِينَ وَجَٰهِدْهُم بِهِۦ جِهَادًۭا كَبِيرًۭا", transliteration: "Fala tutiAAi alkafireena wajahidhum bihi jihadan kabeeran", transliterationB: "Falaa tuti'il kaafireena wa jaahidhum bihee jihaadan kabeeraa", english: "Therefore listen not to the Unbelievers, but strive against them with the utmost strenuousness, with the (Qur'an)", romanUrdu: "Pas (aey Nabi) , ka firon ki baat hargiz na maano aur is Quran ko lekar inke saath jihad-e-kabeer karo" },
    { number: 53, arabic: "۞ وَهُوَ ٱلَّذِى مَرَجَ ٱلْبَحْرَيْنِ هَٰذَا عَذْبٌۭ فُرَاتٌۭ وَهَٰذَا مِلْحٌ أُجَاجٌۭ وَجَعَلَ بَيْنَهُمَا بَرْزَخًۭا وَحِجْرًۭا مَّحْجُورًۭا", transliteration: "Wahuwa allathee maraja albahrayni hatha AAathbun furatun wahatha milhun ojajun wajaAAala baynahuma barzakhan wahijran mahjooran", transliterationB: "Wa Huwal lazee marajal bahraini haazaa 'azbun furaatunw wa haazaa milhun ujaaj; wa ja'ala bainahumaa barzakhanw wa hijram mahjooraa", english: "It is He Who has let free the two bodies of flowing water: One palatable and sweet, and the other salt and bitter; yet has He made a barrier between them, a partition that is forbidden to be passed", romanUrdu: "Aur wahi hai jisne do samandaron ko mila rakkha hai, ek lazeez o shereen(sweet) , dusra talkh o shur (bitter and saltish), aur dono ke darmiyan ek purda hayal hai, ek rukawat hai(insurmountable barrier) jo unhein gud-mud honay se roakey huey hai" },
    { number: 54, arabic: "وَهُوَ ٱلَّذِى خَلَقَ مِنَ ٱلْمَآءِ بَشَرًۭا فَجَعَلَهُۥ نَسَبًۭا وَصِهْرًۭا ۗ وَكَانَ رَبُّكَ قَدِيرًۭا", transliteration: "Wahuwa allathee khalaqa mina almai basharan fajaAAalahu nasaban wasihran wakana rabbuka qadeeran", transliterationB: "Wa Huwal lazee khalaqa minal maaa'i basharran fa ja'alahoo nasaban wa sihraa; wa kaana Rabbuka Qadeeraa", english: "It is He Who has created man from water: then has He established relationships of lineage and marriage: for thy Lord has power (over all things)", romanUrdu: "Aur wahi hai jisne pani se ek bashar (Insaan) paida kiya, phir ussey nasab aur susraal (by blood and by marriage) ke do alag silsile chalaye .Tera Rubb bada hi qudrat wala hai" },
    { number: 55, arabic: "وَيَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَنفَعُهُمْ وَلَا يَضُرُّهُمْ ۗ وَكَانَ ٱلْكَافِرُ عَلَىٰ رَبِّهِۦ ظَهِيرًۭا", transliteration: "WayaAAbudoona min dooni Allahi ma la yanfaAAuhum wala yadurruhum wakana alkafiru AAala rabbihi thaheeran", transliterationB: "Wa ya'budoona min doonil laahi maa laa yanfa'uhum wa laa yadurruhum; wa kaanal kaafiru 'alaa Rabbihee zaheeraa", english: "Yet do they worship, besides Allah, things that can neither profit them nor harm them: and the Misbeliever is a helper (of Evil), against his own Lord", romanUrdu: "Is khuda ko chodh kar log unko poojh rahey hain jo na inko nafaa pahuncha sakte hain na nuqsaan, aur upar se mazeed yeh ke kafir apne Rubb ke muqablay mein har baagi ka madadgaar bana hua hai" },
    { number: 56, arabic: "وَمَآ أَرْسَلْنَٰكَ إِلَّا مُبَشِّرًۭا وَنَذِيرًۭا", transliteration: "Wama arsalnaka illa mubashshiran wanatheeran", transliterationB: "Wa maa arsalnaaka illaa mubashshiranw wa nazeeraa", english: "But thee We only sent to give glad tidings and admonition", romanUrdu: "(Aey Muhammad), tumko to humne bas ek mubashir (khush khabri dene waala) aur nazeer (darr sunane wala) bana kar bheja hai" },
    { number: 57, arabic: "قُلْ مَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ إِلَّا مَن شَآءَ أَن يَتَّخِذَ إِلَىٰ رَبِّهِۦ سَبِيلًۭا", transliteration: "Qul ma asalukum AAalayhi min ajrin illa man shaa an yattakhitha ila rabbihi sabeelan", transliterationB: "Qul maaa as'alukum 'alaihi min ajrin illaa man shaaa'a ai yattakhiza ilaa Rabbihee sabeelaa", english: "Say: \"No reward do I ask of you for it but this: that each one who will may take a (straight) Path to his Lord", romanUrdu: "Insey kehdo ke “ main is kaam par tumse koi ujrat (recompense) nahin maangta, meri ujrat bas yahi hai ke jiska jee chahe woh apne Rubb ka raasta ikhtiyar karle”" },
    { number: 58, arabic: "وَتَوَكَّلْ عَلَى ٱلْحَىِّ ٱلَّذِى لَا يَمُوتُ وَسَبِّحْ بِحَمْدِهِۦ ۚ وَكَفَىٰ بِهِۦ بِذُنُوبِ عِبَادِهِۦ خَبِيرًا", transliteration: "Watawakkal AAala alhayyi allathee la yamootu wasabbih bihamdihi wakafa bihi bithunoobi AAibadihi khabeeran", transliterationB: "Wa tawakkal 'alal Haiyil lazee laa yamootu wa sabbih bihamdih; wa kafaa bihee bizunoobi 'ibaadihee khabeeraa", english: "And put thy trust in Him Who lives and dies not; and celebrate his praise; and enough is He to be acquainted with the faults of His servants", romanUrdu: "Aur (aey Muhammad) us khuda par bharosa rakkho jo zinda hai aur kabhi marne waala nahin, uski hamd ke saath uski tasbeeh karo,apne bandon ke gunaahon se bas usi ka ba-khabar hona kaafi hai" },
    { number: 59, arabic: "ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا فِى سِتَّةِ أَيَّامٍۢ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ ۚ ٱلرَّحْمَٰنُ فَسْـَٔلْ بِهِۦ خَبِيرًۭا", transliteration: "Allathee khalaqa alssamawati waalarda wama baynahuma fee sittati ayyamin thumma istawa AAala alAAarshi alrrahmanu faisal bihi khabeeran", transliterationB: "Allazee khalaqas samaawaati wal arda wa maa bainahumaa fee sittati aiyaamin summmmastawaa 'alal 'Arsh; ar Rahmaanu fas'al bihee khabeeraa", english: "He Who created the heavens and the earth and all that is between, in six days, and is firmly established on the Throne (of Authority): Allah Most Gracious: ask thou, then, about Him of any acquainted (with such things)", romanUrdu: "Woh jisne chey (six) dino mein zameen aur aasmaano ko aur un saari cheezon ko bana kar rakh diya jo aasmaan o zameen ke darmiyaan hain, phir aap hi (qayinaat ke takht e sultanat) ‘Arsh’ par jalwa farma hua. Rehman, uski shaan bas kisi jaanne waley se pucho" },
    { number: 60, arabic: "وَإِذَا قِيلَ لَهُمُ ٱسْجُدُوا۟ لِلرَّحْمَٰنِ قَالُوا۟ وَمَا ٱلرَّحْمَٰنُ أَنَسْجُدُ لِمَا تَأْمُرُنَا وَزَادَهُمْ نُفُورًۭا ۩", transliteration: "Waitha qeela lahumu osjudoo lilrrahmani qaloo wama alrrahmanu anasjudu lima tamuruna wazadahum nufooran", transliterationB: "Wa izaa qeela lahumus judoo lir Rahmaani qaaloo wa mar Rahmaanu anasjudu limaa taamurunaa wa zaadahum nufooraa", english: "When it is said to them, \"Prostrate to (Allah) Most Gracious!\", they say, \"And what is (Allah) Most Gracious? Shall we prostrate to that which thou commandest us?\" And it increases their flight (from the Truth)", romanUrdu: "In logon se jab kaha jata hai ke is Rehman ko sajda karo to kehte hain “Rehman kya hota hai? Kya bas jisey tu kehde usi ko hum sajda karte phirein?” yeh dawat inki nafrat mein ulta aur izafa kardeti hai" },
    { number: 61, arabic: "تَبَارَكَ ٱلَّذِى جَعَلَ فِى ٱلسَّمَآءِ بُرُوجًۭا وَجَعَلَ فِيهَا سِرَٰجًۭا وَقَمَرًۭا مُّنِيرًۭا", transliteration: "Tabaraka allathee jaAAala fee alssamai buroojan wajaAAala feeha sirajan waqamaran muneeran", transliterationB: "Tabaarakal lazee ja'ala fis samaaa'i buroojanw wa ja'ala feehaa siraajanw wa qamaram muneeraa", english: "Blessed is He Who made constellations in the skies, and placed therein a Lamp and a Moon giving light", romanUrdu: "Bada mutabarrak(ba-barakat) hai woh jisne aasmaan mein burj (fortified spheres) banaye aur us mein ek chiraag aur ek chamakta Chand roshan kiya" },
    { number: 62, arabic: "وَهُوَ ٱلَّذِى جَعَلَ ٱلَّيْلَ وَٱلنَّهَارَ خِلْفَةًۭ لِّمَنْ أَرَادَ أَن يَذَّكَّرَ أَوْ أَرَادَ شُكُورًۭا", transliteration: "Wahuwa allathee jaAAala allayla waalnnahara khilfatan liman arada an yaththakkara aw arada shukooran", transliterationB: "Wa huwal lazee ja'alal laila wannahaara khilfatal liman araada ai yazzakkara aw araadaa shookooraa", english: "And it is He Who made the Night and the Day to follow each other: for such as have the will to celebrate His praises or to show their gratitude", romanUrdu: "Wahi hai jisne raat aur din ko ek dusre ka jaanasheen banaya, har us shaks ke liye jo sabaq lena chahe, ya shukar guzaar hona chahe" },
    { number: 63, arabic: "وَعِبَادُ ٱلرَّحْمَٰنِ ٱلَّذِينَ يَمْشُونَ عَلَى ٱلْأَرْضِ هَوْنًۭا وَإِذَا خَاطَبَهُمُ ٱلْجَٰهِلُونَ قَالُوا۟ سَلَٰمًۭا", transliteration: "WaAAibadu alrrahmani allatheena yamshoona AAala alardi hawnan waitha khatabahumu aljahiloona qaloo salaman", transliterationB: "Wa 'ibaadur Rahmaanil lazeena yamshoona 'alal ardi hawnanw wa izaa khaata bahumul jaahiloona qaaloo salaamaa", english: "And the servants of (Allah) Most Gracious are those who walk on the earth in humility, and when the ignorant address them, they say, \"Peace", romanUrdu: "Rehman ke (asli) banday woh hai jo zameen par narm chaal chalte hain aur jaahil unke mooh ko aayein to keh detay hain ke tumko salaam" },
    { number: 64, arabic: "وَٱلَّذِينَ يَبِيتُونَ لِرَبِّهِمْ سُجَّدًۭا وَقِيَٰمًۭا", transliteration: "Waallatheena yabeetoona lirabbihim sujjadan waqiyaman", transliterationB: "Wallazeena yabeetoona li Rabbihim sujjadanw wa qiyaamaa", english: "Those who spend the night in adoration of their Lord prostrate and standing", romanUrdu: "Jo apne Rubb ke huzur sajde aur qayaam mein raatein guzarte hain" },
    { number: 65, arabic: "وَٱلَّذِينَ يَقُولُونَ رَبَّنَا ٱصْرِفْ عَنَّا عَذَابَ جَهَنَّمَ ۖ إِنَّ عَذَابَهَا كَانَ غَرَامًا", transliteration: "Waallatheena yaqooloona rabbana isrif AAanna AAathaba jahannama inna AAathabaha kana gharaman", transliterationB: "Wallazeena yaqooloona Rabbanas rif 'annnaa 'azaaba Jahannama inn 'azaabahaa kaana gharaamaa", english: "Those who say, \"Our Lord! avert from us the Wrath of Hell, for its Wrath is indeed an affliction grievous", romanUrdu: "Jo duaein karte hain ke “Aey hamare Rubb, jahannum ke azaab se humko bacha le, uska azaab to jaan ka laagu hai" },
    { number: 66, arabic: "إِنَّهَا سَآءَتْ مُسْتَقَرًّۭا وَمُقَامًۭا", transliteration: "Innaha saat mustaqarran wamuqaman", transliterationB: "Innahaa saaa'at mustaqarranw wa muqaamaa", english: "Evil indeed is it as an abode, and as a place to rest in", romanUrdu: "Woh to bada hi mustaqar(evil abode) aur muqaam hai”" },
    { number: 67, arabic: "وَٱلَّذِينَ إِذَآ أَنفَقُوا۟ لَمْ يُسْرِفُوا۟ وَلَمْ يَقْتُرُوا۟ وَكَانَ بَيْنَ ذَٰلِكَ قَوَامًۭا", transliteration: "Waallatheena itha anfaqoo lam yusrifoo walam yaqturoo wakana bayna thalika qawaman", transliterationB: "Wallazeena izaaa anfaqoo lam yusrifoo wa lam yaqturoo wa kaana baina zaalika qawaamaa", english: "Those who, when they spend, are not extravagant and not niggardly, but hold a just (balance) between those (extremes)", romanUrdu: "Jo kharch karte hain to na fizool kharchi karte hain na bukhl, balke unka kharch dono intehaaon (extremes) ke darmiyan aitadaal par qayam rehta hai" },
    { number: 68, arabic: "وَٱلَّذِينَ لَا يَدْعُونَ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ وَلَا يَقْتُلُونَ ٱلنَّفْسَ ٱلَّتِى حَرَّمَ ٱللَّهُ إِلَّا بِٱلْحَقِّ وَلَا يَزْنُونَ ۚ وَمَن يَفْعَلْ ذَٰلِكَ يَلْقَ أَثَامًۭا", transliteration: "Waallatheena la yadAAoona maAAa Allahi ilahan akhara wala yaqtuloona alnnafsa allatee harrama Allahu illa bialhaqqi wala yaznoona waman yafAAal thalika yalqa athaman", transliterationB: "Wallazeena laa yad'oona ma'al laahi ilaahan aakhara wa laa yaqtuloonan nafsal latee harramal laahu illaa bilhaqqi wa laa yaznoon; wa mai yaf'al zaalika yalqa asaamaa", english: "Those who invoke not, with Allah, any other god, nor slay such life as Allah has made sacred except for just cause, nor commit fornication; - and any that does this (not only) meets punishment", romanUrdu: "Jo Allah ke siwa kisi aur mabood ko nahin pukarte, Allah ki haraam ki hui kisi jaan ko na-haqq halaak nahin karte, aur na zina (adultery) ke murtakib hotay hain. Yeh kaam jo koi karey woh apne gunaah ka badla payega" },
    { number: 69, arabic: "يُضَٰعَفْ لَهُ ٱلْعَذَابُ يَوْمَ ٱلْقِيَٰمَةِ وَيَخْلُدْ فِيهِۦ مُهَانًا", transliteration: "YudaAAaf lahu alAAathabu yawma alqiyamati wayakhlud feehi muhanan", transliterationB: "Yudaa'af lahul 'azaabu Yawmal Qiyaamati wa yakhlud feehee muhaanaa", english: "(But) the Penalty on the Day of Judgment will be doubled to him, and he will dwell therein in ignominy", romanUrdu: "Qayamat ke roz usko mukarrar azaab diya jayega aur isi mein woh hamesha zillat ke saath pada rahega" },
    { number: 70, arabic: "إِلَّا مَن تَابَ وَءَامَنَ وَعَمِلَ عَمَلًۭا صَٰلِحًۭا فَأُو۟لَٰٓئِكَ يُبَدِّلُ ٱللَّهُ سَيِّـَٔاتِهِمْ حَسَنَٰتٍۢ ۗ وَكَانَ ٱللَّهُ غَفُورًۭا رَّحِيمًۭا", transliteration: "Illa man taba waamana waAAamila AAamalan salihan faolaika yubaddilu Allahu sayyiatihim hasanatin wakana Allahu ghafooran raheeman", transliterationB: "Illaa man taaba wa 'aamana wa 'amila 'amalan saalihan fa ulaaa'ika yubad dilul laahu saiyi aatihim hasanaat; wa kaanal laahu Ghafoorar Raheemaa", english: "Unless he repents, believes, and works righteous deeds, for Allah will change the evil of such persons into good, and Allah is Oft-Forgiving, Most Merciful", romanUrdu: "Illa yeh ke koi (in gunaahon ke baad) toubah kar chuka ho aur iman laa kar amal e saleeh karne laga ho, aisey logon ki buraiyon ko Allah bhalaiyon se badal dega aur woh bada gafoor o raheem hai" },
    { number: 71, arabic: "وَمَن تَابَ وَعَمِلَ صَٰلِحًۭا فَإِنَّهُۥ يَتُوبُ إِلَى ٱللَّهِ مَتَابًۭا", transliteration: "Waman taba waAAamila salihan fainnahu yatoobu ila Allahi mataban", transliterationB: "Wa man taaba wa 'amila saalihan fa innnahoo yatoobu ilal laahi mataabaa", english: "And whoever repents and does good has truly turned to Allah with an (acceptable) conversion", romanUrdu: "Jo shaks toubah karke neik amali ikhtiyar karta hai woh to Allah ki taraf palat aata hai jaisa ke palatne ka haqq hai" },
    { number: 72, arabic: "وَٱلَّذِينَ لَا يَشْهَدُونَ ٱلزُّورَ وَإِذَا مَرُّوا۟ بِٱللَّغْوِ مَرُّوا۟ كِرَامًۭا", transliteration: "Waallatheena la yashhadoona alzzoora waitha marroo biallaghwi marroo kiraman", transliterationB: "Wallazeena laa yash hadoonaz zoora wa izaa marroo billaghwi marroo kiraamaa", english: "Those who witness no falsehood, and, if they pass by futility, they pass by it with honourable (avoidance)", romanUrdu: "(Aur Rehman ke bandey woh hain) jo jhoot ke gawaah nahin bante aur kisi lagv (fizul/vain) cheez par unka guzar ho jaye to shareef aadmiyon ki tarah guzar jatey hain" },
    { number: 73, arabic: "وَٱلَّذِينَ إِذَا ذُكِّرُوا۟ بِـَٔايَٰتِ رَبِّهِمْ لَمْ يَخِرُّوا۟ عَلَيْهَا صُمًّۭا وَعُمْيَانًۭا", transliteration: "Waallatheena itha thukkiroo biayati rabbihim lam yakhirroo AAalayha summan waAAumyanan", transliterationB: "Wallazeena izaa zukkiroo bi Aayaati Rabbihim lam yakhirroo 'alaihaa summanw wa'umyaanaa", english: "Those who, when they are admonished with the Signs of their Lord, droop not down at them as if they were deaf or blind", romanUrdu: "Jinhein agar unke Rubb ki aayat suna kar naseehat ki jati hai to woh uspar andhey aur behre bankar nahin reh jatey" },
    { number: 74, arabic: "وَٱلَّذِينَ يَقُولُونَ رَبَّنَا هَبْ لَنَا مِنْ أَزْوَٰجِنَا وَذُرِّيَّٰتِنَا قُرَّةَ أَعْيُنٍۢ وَٱجْعَلْنَا لِلْمُتَّقِينَ إِمَامًا", transliteration: "Waallatheena yaqooloona rabbana hab lana min azwajina wathurriyyatina qurrata aAAyunin waijAAalna lilmuttaqeena imaman", transliterationB: "Wallazeena yaqooloona Rabbanaa hab lanaa min azwaajinaa wa zurriyaatinaa qurrata a'yuninw waj 'alnaa lilmuttaqeena Imaamaa", english: "And those who pray, \"Our Lord! Grant unto us wives and offspring who will be the comfort of our eyes, and give us (the grace) to lead the righteous", romanUrdu: "Jo duaein maanga karte hain ke, “Aey hamare Rubb, humein apni biwiyon aur apni aulaad se aankhon ki thandak de, aur humko parheizgaaron ka imam bana.”" },
    { number: 75, arabic: "أُو۟لَٰٓئِكَ يُجْزَوْنَ ٱلْغُرْفَةَ بِمَا صَبَرُوا۟ وَيُلَقَّوْنَ فِيهَا تَحِيَّةًۭ وَسَلَٰمًا", transliteration: "Olaika yujzawna alghurfata bima sabaroo wayulaqqawna feeha tahiyyatan wasalaman", transliterationB: "Ulaaa'ika yujzawnal ghurfata bimaa sabaroo wa yulaqqawna feehaa tahiyyatanw wa salaamaa", english: "Those are the ones who will be rewarded with the highest place in heaven, because of their patient constancy: therein shall they be met with salutations and peace", romanUrdu: "Yeh hain woh log jo apne sabr ka phal manzil-e-buland ki shakal mein payenge, aadaab o tasleemaat se unka istaqbaal hoga" },
    { number: 76, arabic: "خَٰلِدِينَ فِيهَا ۚ حَسُنَتْ مُسْتَقَرًّۭا وَمُقَامًۭا", transliteration: "Khalideena feeha hasunat mustaqarran wamuqaman", transliterationB: "Khaalideena feehaa; hasunat mustaqarranw wa muqaamaa", english: "Dwelling therein;- how beautiful an abode and place of rest", romanUrdu: "Woh hamesha hamesha wahan rahenge. Kya hi accha hai woh mustaqar (excellent abode) aur woh muqaam" },
    { number: 77, arabic: "قُلْ مَا يَعْبَؤُا۟ بِكُمْ رَبِّى لَوْلَا دُعَآؤُكُمْ ۖ فَقَدْ كَذَّبْتُمْ فَسَوْفَ يَكُونُ لِزَامًۢا", transliteration: "Qul ma yaAAbao bikum rabbee lawla duAAaokum faqad kaththabtum fasawfa yakoonu lizaman", transliterationB: "Qul maa ya'ba'u bikum Rabbee law laa du'aaa'ukum faqad kazzabtum fasawfa yakoonu lizaamaa", english: "Say (to the Rejecters): \"My Lord is not uneasy because of you if ye call not on Him: But ye have indeed rejected (Him), and soon will come the inevitable (punishment)", romanUrdu: "(Aey Muhammad), logon se kaho, “mere Rubb ko tumhari kya haajat padi hai agar tum usko na pukaro. Ab ke tumne jhutla diya hai, anqareeb woh saza paogey ke jaan chudhani muhaal (never be able to avoid) hogi”" }
  ]
};
